// Define a function to split the input string into media queries
function splitMediaQueries(input) {
    let mediaQueries = input.split('\n');
    return mediaQueries;
}

// Define a function to compare the priority of two media queries
function compareMediaQueries(mediaQuery1, mediaQuery2) {
    let featureValue1 = parseInt(mediaQuery1.split(' and ')[1].split(': ')[1]);
    let featureValue2 = parseInt(mediaQuery2.split(' and ')[1].split(': ')[1]);
    if (featureValue1 > featureValue2) {
        return 1;
    } else if (featureValue1 < featureValue2) {
        return -1;
    } else {
        return 0;
    }
}

// Define a function to fix the media query priority
function fixMediaQueryPriority(input) {
    let mediaQueries = splitMediaQueries(input);
    return mediaQueries.sort(compareMediaQueries).join('\n');
}

