// Solution
function fixMediaQueryPriority(input) {
    let mediaQueries = input.split('\n');
    return mediaQueries.sort((mediaQuery1, mediaQuery2) => {
        let featureValue1 = parseInt(mediaQuery1.split(' and ')[1].split(': ')[1]);
        let featureValue2 = parseInt(mediaQuery2.split(' and ')[1].split(': ')[1]);
        return featureValue1 - featureValue2;
    }).join('\n');
}

